const parts = [$.input.topic, $.input.communitySource];
const staticTerms = "{{}} discussion opinions {{}}";
return { query: parts.filter(Boolean).join(" ") + " " + staticTerms };

const results = $.steps.searchCommunity.response.results || [];
const maxD = parseInt($.input.maxDiscussions || '15', 10);
const selected = results.slice(0, maxD);

let discussionText = '';
selected.forEach((r, i) => {
  discussionText += '=== DISCUSSION ' + (i + 1) + ' ===\n';
  discussionText += 'Title: ' + (r.title || 'Untitled') + '\n';
  discussionText += 'URL: ' + r.url + '\n';
  if (r.publishedDate) discussionText += 'Date: ' + r.publishedDate + '\n';
  discussionText += 'Content:\n' + (r.text || '').slice(0, 1500) + '\n\n';
});

return { discussionText, discussionCount: selected.length, sources: selected.map(r => ({ title: r.title || r.url, url: r.url })) };

const d = $.steps.compileDiscussions.output;
const topic = $.input.topic;

let prompt = 'You are a community insights analyst. Analyze the following community discussions about "' + topic + '" and extract structured insights.\n\n';
prompt += 'TOPIC: ' + topic + '\n';
prompt += 'DISCUSSIONS ANALYZED: ' + d.discussionCount + '\n\n';
prompt += 'COMMUNITY DISCUSSIONS:\n' + d.discussionText + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '1. Identify the top 3-5 recurring themes across discussions\n';
prompt += '2. Analyze overall sentiment (positive, neutral, negative) with a score 0-100\n';
prompt += '3. Extract specific pain points and feature requests mentioned\n';
prompt += '4. Identify key influencers or frequently cited opinions\n';
prompt += '5. Note any emerging trends or shifts in community opinion\n';
prompt += '6. Create per-discussion sentiment breakdown\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "overallSentiment": { "label": "positive|neutral|negative|mixed", "score": 65 },\n';
prompt += '  "themes": [\n';
prompt += '    { "name": "theme name", "frequency": "high|medium|low", "sentiment": "positive|neutral|negative", "description": "brief description" }\n';
prompt += '  ],\n';
prompt += '  "painPoints": ["pain point 1", "pain point 2"],\n';
prompt += '  "featureRequests": ["request 1", "request 2"],\n';
prompt += '  "emergingTrends": ["trend 1", "trend 2"],\n';
prompt += '  "discussions": [\n';
prompt += '    { "index": 1, "title": "title", "sentiment": "positive|neutral|negative", "keyTakeaway": "one line summary" }\n';
prompt += '  ],\n';
prompt += '  "executiveSummary": "2-3 sentence overview of community sentiment"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { overallSentiment: { label: 'unknown', score: 0 }, themes: [], painPoints: [], featureRequests: [], emergingTrends: [], discussions: [], executiveSummary: raw }; }

const ai = $.steps.parseAI.output;
const date = new Date().toISOString().split('T')[0];

const themeRows = (ai.themes || []).map((t, i) => ({
  '#': i + 1,
  'Type': 'Theme',
  'Name': t.name || '',
  'Frequency': t.frequency || '',
  'Sentiment': t.sentiment || '',
  'Description': t.description || '',
  'Date': date
}));

const painRows = (ai.painPoints || []).map((p, i) => ({
  '#': themeRows.length + i + 1,
  'Type': 'Pain Point',
  'Name': p,
  'Frequency': '',
  'Sentiment': 'negative',
  'Description': '',
  'Date': date
}));

const requestRows = (ai.featureRequests || []).map((r, i) => ({
  '#': themeRows.length + painRows.length + i + 1,
  'Type': 'Feature Request',
  'Name': r,
  'Frequency': '',
  'Sentiment': 'neutral',
  'Description': '',
  'Date': date
}));

const trendRows = (ai.emergingTrends || []).map((t, i) => ({
  '#': themeRows.length + painRows.length + requestRows.length + i + 1,
  'Type': 'Trend',
  'Name': t,
  'Frequency': '',
  'Sentiment': '',
  'Description': '',
  'Date': date
}));

const sheetData = themeRows.concat(painRows).concat(requestRows).concat(trendRows);

return { sheetData, summary: ai.overallSentiment || {}, executiveSummary: ai.executiveSummary || '' };

const ai = $.steps.parseAI.output;
const topic = $.input.topic;
const dCount = $.steps.compileDiscussions.output.discussionCount;
const sentiment = ai.overallSentiment || {};

const sentEmoji = sentiment.label === 'positive' ? ':large_green_circle:' : sentiment.label === 'negative' ? ':red_circle:' : sentiment.label === 'mixed' ? ':large_orange_circle:' : ':large_yellow_circle:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Community Insights Report' } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Topic:*\n' + topic },
  { type: 'mrkdwn', text: '*Discussions Analyzed:*\n' + dCount }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Overall Sentiment:*\n' + sentEmoji + ' ' + (sentiment.label || 'unknown') },
  { type: 'mrkdwn', text: '*Sentiment Score:*\n' + (sentiment.score || 0) + '/100' }
] });
blocks.push({ type: 'divider' });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Executive Summary:*\n' + (ai.executiveSummary || 'No summary available.').slice(0, 1800) } });
blocks.push({ type: 'divider' });

if (ai.themes && ai.themes.length > 0) {
  let themeText = '*Key Themes:*\n';
  ai.themes.slice(0, 5).forEach((t, i) => { themeText += (i + 1) + '. *' + t.name + '* (' + t.frequency + ', ' + t.sentiment + ') - ' + (t.description || '').slice(0, 100) + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: themeText.slice(0, 1800) } });
}

if (ai.painPoints && ai.painPoints.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Pain Points:*\n' + ai.painPoints.slice(0, 5).map((p, i) => (i + 1) + '. ' + p).join('\n') } });
}

if (ai.emergingTrends && ai.emergingTrends.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Emerging Trends:*\n' + ai.emergingTrends.slice(0, 3).map((t, i) => (i + 1) + '. ' + t).join('\n') } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa + Claude AI + Google Sheets' }] });

const fallback = 'Community insights for ' + topic + ': ' + (sentiment.label || 'unknown') + ' sentiment (' + dCount + ' discussions)';
return { blocks, fallback };
